const req = $input.first().json;
return [{ json: {
  client_id: req.query?.client_id ?? null,
  timestamp: req.headers['x-caiac-timestamp'],
  signature: req.headers['x-caiac-signature'],
  token: req.headers['x-caiac-token'] ?? req.query?.token
}}];

const auth = $input.first().json;
if (!auth.is_caiac_staff) throw new Error('Forbidden: CAIAC staff only');
const req = $('Receive Request').first().json;
const period = req.query?.period ?? new Date().toISOString().slice(0, 7);
const slug = req.query?.slug ?? null;
return [{ json: { period, slug } }];
